    raw.messages
  )
    .filter(text => text && typeof text === 'object')
    .sort((a, b) => {
      const da = parseDate(getTextDate(a))?.getTime() || 0;
      const db = parseDate(getTextDate(b))?.getTime() || 0;
      return db - da;
    });

  const latestOutboundText = texts.find(isOutboundTextToLead) || null;
  const latestOutboundTextDate = latestOutboundText
    ? toIsoOrBlank(getTextDate(latestOutboundText))
    : '';

  const fallbackText = getFallbackLastSentText(originalLead);

  /**
   * Resultado final:
   * 1. Si el endpoint de textos trae un texto saliente, usa ese dato.
   * 2. Si el endpoint falla, viene vacío o no trae textos salientes, usa people.lastSentText.
   */
  const finalOutboundTextDate = latestOutboundTextDate || fallbackText.date || '';
  const finalOutboundTextId = latestOutboundText?.id || fallbackText.id || '';

  const textDateSource = latestOutboundTextDate
    ? 'texts_api'
    : fallbackText.source || '';

  return {
    json: {
      ...originalLead,

      lastOutboundTextDate: finalOutboundTextDate
        ? toIsoOrBlank(finalOutboundTextDate)
        : '',

      lastOutboundTextDays: finalOutboundTextDate
        ? daysSince(finalOutboundTextDate)
        : '',

      lastOutboundTextId: finalOutboundTextId,

      textsChecked: texts.length,

      textsApiTotal:
        body._metadata?.total ??
        raw._metadata?.total ??
        texts.length,

      textsApiHasNextPage: Boolean(
        body._metadata?.next ||
        body._metadata?.nextLink ||
        raw._metadata?.next ||
        raw._metadata?.nextLink
      ),

      textsApiError: apiError,
      textsApiStatusCode: statusCode || '',
      textsApiErrorMessage: errorMessage || '',

      textDateSource,
    }
  };
});

const items = $input.all();
const now = new Date();
const MS_PER_DAY = 1000 * 60 * 60 * 24;

function parseDate(value) {
  if (!value) return null;

  if (value instanceof Date && !Number.isNaN(value.getTime())) {
    return value;
  }

  const date = new Date(value);
  return Number.isNaN(date.getTime()) ? null : date;
}

function toIsoOrBlank(value) {
  const date = parseDate(value);
  return date ? date.toISOString() : '';
}

function daysSince(value) {
  const date = parseDate(value);
  if (!date) return '';

  const diff = now.getTime() - date.getTime();
  if (diff < 0) return 0;

  return Math.floor(diff / MS_PER_DAY);
}

function ageLabel(value) {
  const date = parseDate(value);
  if (!date) return '';

  const diff = now.getTime() - date.getTime();
  if (diff < 0) return '0 days, 0 hours';

  const days = Math.floor(diff / MS_PER_DAY);
  const hours = Math.floor((diff % MS_PER_DAY) / (1000 * 60 * 60));

  return `${days} days, ${hours} hours`;
}

function norm(value) {
  return String(value || '').trim().toLowerCase();
}

function isValidDate(value) {
  return Boolean(parseDate(value));
}

function getPeople(item) {
  return item.people || {};
}

function getLastCommunicationRaw(people, item) {
  return people.lastCommunication || item.lastCommunication || null;
}

function getLastCommunicationDate(people, item) {
  const lastCommunication = getLastCommunicationRaw(people, item);

  if (!lastCommunication) return '';

  if (typeof lastCommunication === 'string') {
    return lastCommunication;
  }

  if (typeof lastCommunication === 'object') {
    return (
      lastCommunication.date ||
      lastCommunication.created ||
      lastCommunication.createdAt ||
      lastCommunication.sentAt ||
      lastCommunication.sent ||
      lastCommunication.updated ||
      lastCommunication.updatedAt ||
      ''
    );
  }

  return '';
}

function getLastCommunicationType(people, item) {
  const lastCommunication = getLastCommunicationRaw(people, item);

  if (lastCommunication && typeof lastCommunication === 'object') {
    return lastCommunication.type || '';
  }

  return '';
}

function getLastCommunicationDirection(people, item) {
  const lastCommunication = getLastCommunicationRaw(people, item);

  if (lastCommunication && typeof lastCommunication === 'object') {
    return lastCommunication.direction || '';
  }

  return '';
}

function getLastCommunicationId(people, item) {
  const lastCommunication = getLastCommunicationRaw(people, item);

  if (lastCommunication && typeof lastCommunication === 'object') {
    return lastCommunication.id || '';
  }

  return '';
}

function pickMostRecent(candidates) {
  const validCandidates = candidates
    .filter(candidate => candidate && isValidDate(candidate.date))
    .sort((a, b) => {
      const da = parseDate(a.date)?.getTime() || 0;
      const db = parseDate(b.date)?.getTime() || 0;
      return db - da;
    });

  return validCandidates[0] || null;
}

function buildCallCandidate(people, item) {
  // Prioridad 1: llamada efectiva calculada desde endpoint /calls.
  if (isValidDate(item.lastEffectiveCallDate)) {
    return {
      type: 'CALL',
      source: 'calls_api_effective_call',
      confidence: 'HIGH',
      date: item.lastEffectiveCallDate,
      id: item.lastEffectiveCallId || '',
      reason: 'Se tomó la última llamada efectiva detectada desde el endpoint de llamadas.',
      priorityGroup: 'CALL_OR_TEXT',
    };
  }

  // Respaldo: Last Call del perfil FUB.
  if (isValidDate(people.lastCall || item.lastCall)) {
    return {
      type: 'CALL_PROFILE_FALLBACK',
      source: 'people.lastCall',
      confidence: 'MEDIUM',
      date: people.lastCall || item.lastCall || '',
      id: people.lastCallId || item.lastCallId || '',
      reason: 'No hubo llamada efectiva desde API; se tomó Last Call del perfil.',
      priorityGroup: 'CALL_OR_TEXT',
    };
  }

  return null;
}

function buildTextCandidate(people, item) {
  // Prioridad 1: texto calculado desde endpoint /textMessages o fallback ya procesado.
  if (isValidDate(item.lastOutboundTextDate)) {
    return {
      type: 'TEXT',
      source: item.textDateSource || 'texts_api_or_people_lastSentText',
      confidence: item.textDateSource === 'texts_api' ? 'HIGH' : 'MEDIUM',
      date: item.lastOutboundTextDate,
      id: item.lastOutboundTextId || '',
      reason: item.textDateSource === 'texts_api'
        ? 'Se tomó el último texto saliente detectado desde el endpoint de textos.'
        : 'Se tomó el último texto saliente desde respaldo del perfil.',
      priorityGroup: 'CALL_OR_TEXT',
    };
  }

  // Respaldo: Last Text / Last Sent Text del perfil FUB.
  if (isValidDate(people.lastSentText || item.lastSentText || people.lastText || item.lastText)) {
    return {
      type: 'TEXT_PROFILE_FALLBACK',
      source: 'people.lastSentText',
      confidence: 'MEDIUM',
      date: people.lastSentText || item.lastSentText || people.lastText || item.lastText || '',
      id: people.lastSentTextId || item.lastSentTextId || people.lastTextId || item.lastTextId || '',
      reason: 'No hubo texto válido desde API; se tomó Last Text del perfil.',
      priorityGroup: 'CALL_OR_TEXT',
    };
  }

  return null;
}

function buildCommunicationCandidate(people, item) {
  const communicationDate = getLastCommunicationDate(people, item);

  if (!isValidDate(communicationDate)) return null;

  return {
    type: 'COMMUNICATION_FALLBACK',
    source: 'people.lastCommunication',
    confidence: 'LOW',
    date: communicationDate,
    id: getLastCommunicationId(people, item),
    reason: 'No hubo Last Call ni Last Text disponible; se tomó Last Communication como criterio válido.',
    priorityGroup: 'COMMUNICATION_ONLY',
    communicationType: getLastCommunicationType(people, item),
    communicationDirection: getLastCommunicationDirection(people, item),
  };
}

function resolveWinner(item) {
  const people = getPeople(item);

  const callCandidate = buildCallCandidate(people, item);
  const textCandidate = buildTextCandidate(people, item);
  const communicationCandidate = buildCommunicationCandidate(people, item);

  const callOrTextCandidates = [callCandidate, textCandidate].filter(Boolean);
  const allCandidates = [callCandidate, textCandidate, communicationCandidate].filter(Boolean);

  /**
   * Salvaguarda 1:
   * Si solo existe un dato entre Last Call, Last Text o Last Communication,
   * se toma automáticamente ese único dato.
   */
  if (allCandidates.length === 1) {
    return allCandidates[0];
  }

  /**
   * Regla principal:
   * Si existe Last Call y/o Last Text, se elige el más reciente entre esos dos.
   * Last Communication NO compite contra Call/Text cuando Call/Text existen.
   */
  if (callOrTextCandidates.length > 0) {
    return pickMostRecent(callOrTextCandidates);
  }

  /**
   * Salvaguarda 2:
   * Si no hay Last Call ni Last Text, pero sí Last Communication,
   * Last Communication se usa como criterio válido.
   */
  if (communicationCandidate) {
    return communicationCandidate;
  }

  return null;
}

function buildFinalResult(item) {
  const people = getPeople(item);
  const winner = resolveWinner(item);

  if (!winner) {
    return {
      finalLastCommunicationDate: '',
      finalLastCommunicationDays: '',
      finalLastCommunicationLabel: '',
      finalLastCommunicationType: '',
      finalLastCommunicationSource: '',
      finalLastCommunicationConfidence: 'NONE',
      finalLastCommunicationReason: 'No se encontró fecha válida en Last Call, Last Text ni Last Communication.',
      finalLastCommunicationId: '',
      finalLastCommunicationPriorityGroup: '',
      finalLastCommunicationRawType: '',
      finalLastCommunicationRawDirection: '',
      finalCommunicationDecisionRule: 'NO_VALID_DATA',
    };
  }

  const finalDateIso = toIsoOrBlank(winner.date);

  return {
    finalLastCommunicationDate: finalDateIso,
    finalLastCommunicationDays: daysSince(finalDateIso),
    finalLastCommunicationLabel: ageLabel(finalDateIso),
    finalLastCommunicationType: winner.type,
    finalLastCommunicationSource: winner.source,
    finalLastCommunicationConfidence: winner.confidence,
    finalLastCommunicationReason: winner.reason,
    finalLastCommunicationId: winner.id || '',
    finalLastCommunicationPriorityGroup: winner.priorityGroup || '',
    finalLastCommunicationRawType: winner.communicationType || '',
    finalLastCommunicationRawDirection: winner.communicationDirection || '',
    finalCommunicationDecisionRule:
      winner.priorityGroup === 'CALL_OR_TEXT'
        ? 'CALL_OR_TEXT_WINS_BY_DATE'
        : 'COMMUNICATION_USED_BECAUSE_CALL_AND_TEXT_EMPTY',
  };
}

return items.map((item) => {
  const json = item.json || {};
  const people = json.people || {};
  const resolved = buildFinalResult(json);

  return {
    json: {
      ...json,

      ...resolved,

      // Diagnóstico de candidatos usados para validar en pruebas.
      candidateLastEffectiveCallDate: json.lastEffectiveCallDate || '',
      candidateLastEffectiveCallId: json.lastEffectiveCallId || '',

      candidatePeopleLastCall: people.lastCall || json.lastCall || '',
      candidatePeopleLastCallId: people.lastCallId || json.lastCallId || '',

      candidateLastOutboundTextDate: json.lastOutboundTextDate || '',
      candidateLastOutboundTextId: json.lastOutboundTextId || '',

      candidatePeopleLastSentText:
        people.lastSentText ||
        json.lastSentText ||
        people.lastText ||
        json.lastText ||
        '',

      candidatePeopleLastSentTextId:
        people.lastSentTextId ||
        json.lastSentTextId ||
        people.lastTextId ||
        json.lastTextId ||
        '',

      candidatePeopleLastCommunication:
        getLastCommunicationDate(people, json),

      candidatePeopleLastCommunicationType:
        getLastCommunicationType(people, json),

      candidatePeopleLastCommunicationDirection:
        getLastCommunicationDirection(people, json),
    },
  };
});
